// ─────────────────────────────────────────────────────────────────
//  FIREBASE SETUP — paste your real config values below
//  Console: https://console.firebase.google.com
//  Enable Firestore + Storage in your project
// ─────────────────────────────────────────────────────────────────

import { initializeApp } from 'firebase/app';
import {
  getFirestore,
  collection,
  addDoc,
  updateDoc,
  deleteDoc,
  doc,
  query,
  orderBy,
  onSnapshot,
  serverTimestamp,
} from 'firebase/firestore';
import {
  getStorage,
  ref,
  uploadString,
  getDownloadURL,
  deleteObject,
} from 'firebase/storage';

const firebaseConfig = {
  apiKey:            "REPLACE_WITH_YOUR_API_KEY",
  authDomain:        "REPLACE_WITH_YOUR_AUTH_DOMAIN",
  projectId:         "REPLACE_WITH_YOUR_PROJECT_ID",
  storageBucket:     "REPLACE_WITH_YOUR_STORAGE_BUCKET",
  messagingSenderId: "REPLACE_WITH_YOUR_MESSAGING_SENDER_ID",
  appId:             "REPLACE_WITH_YOUR_APP_ID",
};

const app        = initializeApp(firebaseConfig);
export const db  = getFirestore(app);
export const storage = getStorage(app);

// ── helpers ────────────────────────────────────────────────────────
const col  = (name) => collection(db, name);
const docRef = (col, id) => doc(db, col, id);

function toDate(ts) {
  return ts
    ? ts.toDate().toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' })
    : '';
}

function subscribe(colName, orderField, callback) {
  const q = query(col(colName), orderBy(orderField, 'desc'));
  return onSnapshot(q, snap =>
    callback(snap.docs.map(d => ({ id: d.id, ...d.data(), date: toDate(d.data()[orderField]) })))
  );
}

// ══════════════════════════════════════════════════════════════════
//  WISHES
// ══════════════════════════════════════════════════════════════════
export const subscribeToWishes = (cb) => subscribe('wishes', 'createdAt', cb);

export async function addWish({ name, message }) {
  return addDoc(col('wishes'), { name, message, likes: 0, createdAt: serverTimestamp() });
}

export async function likeWish(id, currentLikes) {
  return updateDoc(docRef('wishes', id), { likes: currentLikes + 1 });
}

export async function deleteWish(id) {
  return deleteDoc(docRef('wishes', id));
}

// ══════════════════════════════════════════════════════════════════
//  MEMORIES
// ══════════════════════════════════════════════════════════════════
export const subscribeToMemories = (cb) => subscribe('memories', 'createdAt', cb);

export async function addMemory({ title, body }) {
  return addDoc(col('memories'), { title, body, createdAt: serverTimestamp() });
}

export async function deleteMemory(id) {
  return deleteDoc(docRef('memories', id));
}

// ══════════════════════════════════════════════════════════════════
//  GUESTS
// ══════════════════════════════════════════════════════════════════
export const subscribeToGuests = (cb) => subscribe('guests', 'createdAt', cb);

export async function addGuest({ name, initials, roleKey }) {
  return addDoc(col('guests'), { name, initials, roleKey, createdAt: serverTimestamp() });
}

export async function deleteGuest(id) {
  return deleteDoc(docRef('guests', id));
}

// ══════════════════════════════════════════════════════════════════
//  PHOTOS  (base64 → Firebase Storage, metadata → Firestore)
// ══════════════════════════════════════════════════════════════════
export const subscribeToPhotos = (cb) => {
  const q = query(col('photos'), orderBy('createdAt', 'desc'));
  return onSnapshot(q, snap =>
    cb(snap.docs.map(d => ({ id: d.id, ...d.data(), date: toDate(d.data().createdAt) })))
  );
};

export async function uploadPhoto({ name, dataURL }) {
  // 1. upload image to Firebase Storage
  const path    = `photos/${Date.now()}_${name}`;
  const fileRef = ref(storage, path);
  await uploadString(fileRef, dataURL, 'data_url');
  const url = await getDownloadURL(fileRef);

  // 2. save URL + metadata to Firestore
  const docSnap = await addDoc(col('photos'), {
    name,
    url,
    storagePath: path,
    createdAt: serverTimestamp(),
  });
  return { id: docSnap.id, name, url, storagePath: path };
}

export async function deletePhoto(id, storagePath) {
  // delete from Storage
  try { await deleteObject(ref(storage, storagePath)); } catch (_) { /* already gone */ }
  // delete from Firestore
  return deleteDoc(docRef('photos', id));
}
